// Schema-shape projection per EvaluatorOutput. Validates RoutingDecision +
// Severity + issue_type enums; ensures evaluator_score = sum(criteria).
// Passes through unresolved_sources and schema_errors as the spec requires.

const response = $input.item.json;
const request = $('Build Evaluator Request').item.json;

let content = response.choices?.[0]?.message?.content;
if (Array.isArray(content)) {
  content = content.map((p) => p?.text || '').join('');
}
if (typeof content !== 'string' || !content.trim()) {
  throw new Error('Evaluator response missing message content.');
}

content = content.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (err) {
  throw new Error(`Evaluator JSON parse failed: ${err.message}\nRaw content: ${content.slice(0, 500)}`);
}

const VALID_ROUTING = ['complete', 'complete_high_confidence', 'flagged_for_review'];
const VALID_SEVERITY = ['HIGH', 'MEDIUM', 'LOW'];
const VALID_ISSUE_TYPE = [
  'potential_hallucination',
  'missing_citation',
  'unacknowledged_contradiction',
  'ignored_red_flag',
  'incoherent_recommendation',
  'strategic_incoherence',
  'other',
];

function clampInt(v, lo, hi) {
  if (typeof v !== 'number' || Number.isNaN(v)) return null;
  const n = Math.round(v);
  if (n < lo) return lo;
  if (n > hi) return hi;
  return n;
}

const cs = parsed.criteria_scores || {};
const criteriaScores = {
  citation_completeness: clampInt(cs.citation_completeness, 0, 10) ?? 0,
  contradiction_acknowledgment: clampInt(cs.contradiction_acknowledgment, 0, 10) ?? 0,
  missing_information_coverage: clampInt(cs.missing_information_coverage, 0, 10) ?? 0,
  red_flag_propagation: clampInt(cs.red_flag_propagation, 0, 10) ?? 0,
  reasoning_coherence: clampInt(cs.reasoning_coherence, 0, 10) ?? 0,
  hallucination_check: clampInt(cs.hallucination_check, 0, 10) ?? 0,
};
const computedTotal = Object.values(criteriaScores).reduce((a, b) => a + b, 0);
// Honor model's evaluator_score if it matches the sum; otherwise use the
// computed sum as authoritative (the prompt says they MUST equal).
let evaluatorScore = clampInt(parsed.evaluator_score, 0, 60);
if (evaluatorScore == null || evaluatorScore !== computedTotal) {
  evaluatorScore = computedTotal;
}

const criticalIssues = Array.isArray(parsed.critical_issues)
  ? parsed.critical_issues
      .filter((x) => x && typeof x === 'object')
      .map((x) => ({
        issue_type: VALID_ISSUE_TYPE.includes(x.issue_type) ? x.issue_type : null,
        description: typeof x.description === 'string' ? x.description : '',
        severity: VALID_SEVERITY.includes(x.severity) ? x.severity : null,
      }))
      .filter((x) => x.issue_type && x.severity && x.description.length > 0)
  : [];

// Routing: threshold rule + HIGH critical_issue override.
let routingDecision = VALID_ROUTING.includes(parsed.routing_decision) ? parsed.routing_decision : null;
const hasHighCritical = criticalIssues.some((c) => c.severity === 'HIGH');
if (hasHighCritical) {
  routingDecision = 'flagged_for_review';
} else if (routingDecision == null) {
  if (evaluatorScore < 35) routingDecision = 'flagged_for_review';
  else if (evaluatorScore < 50) routingDecision = 'complete';
  else routingDecision = 'complete_high_confidence';
}

const evaluatorOutput = {
  evaluator_score: evaluatorScore,
  criteria_scores: criteriaScores,
  critical_issues: criticalIssues,
  routing_decision: routingDecision,
  schema_errors: Array.isArray(parsed.schema_errors) ? parsed.schema_errors : (request.schema_errors || []),
  unresolved_sources: Array.isArray(parsed.unresolved_sources) ? parsed.unresolved_sources : (request.citation_validity?.unresolved_sources || []),
};

return {
  json: {
    run_id: request.run_id,
    deal_id: request.deal_id,
    company_name: request.company_name,
    timestamp_started: request.timestamp_started,
    source_manifest: request.source_manifest,
    extraction_outputs: request.extraction_outputs,
    contradiction_output: request.contradiction_output,
    gap_analysis_output: request.gap_analysis_output,
    red_flag_detector_output: request.red_flag_detector_output,
    portfolio_fit_output: request.portfolio_fit_output,
    memo_output: request.memo_output,
    citation_validity: request.citation_validity,
    evaluator_output: evaluatorOutput,
    llm_usage: response.usage || {},
    llm_model: response.model || $env.ALICLOUD_MODEL,
    timestamp_completed: new Date().toISOString(),
  },
};

// Build Supabase Record — Phase 3 task 3.15
// Assembles the row JSON for INSERT into public.deal_memos per
// schemas/supabase-schema.sql. The status field maps from the
// Evaluator's routing_decision (per design plan §2.11 state machine).

const upstream = $input.item.json;
if (!upstream) throw new Error('Build Supabase Record received empty input.');

const memo = upstream.memo_output || {};
const evaluator = upstream.evaluator_output || {};
const routing = evaluator.routing_decision || 'flagged_for_review';

// status enum maps directly from routing_decision
const status = routing;

// source_documents: assemble from source_manifest + Coordinator's documents
// metadata. The Coordinator emits documents on the run-level item but we
// only have source_manifest (string array) downstream. Reach back to
// Coordinator for the richer shape.
const coordinator = $('Coordinator').all()[0]?.json;
const sourceDocuments = coordinator?.documents || (upstream.source_manifest || []).map((name) => ({ source_name: name }));

const evaluatorFeedback = {
  criteria_scores: evaluator.criteria_scores || null,
  critical_issues: evaluator.critical_issues || [],
  routing_decision: routing,
  schema_errors: evaluator.schema_errors || [],
  unresolved_sources: evaluator.unresolved_sources || [],
};

const row = {
  run_id: upstream.run_id,
  deal_id: upstream.deal_id,
  company_name: upstream.company_name,
  status,
  executive_summary: memo.executive_summary,
  recommendation: memo.recommendation,
  recommendation_rationale: memo.recommendation_rationale,
  company_snapshot: memo.company_snapshot || null,
  investment_thesis: memo.investment_thesis,
  key_strengths: memo.key_strengths || [],
  key_risks: memo.key_risks || [],
  contradictions: memo.contradictions || [],
  missing_information: memo.missing_information || [],
  red_flags: memo.red_flags || [],
  portfolio_fit: memo.portfolio_fit || null,
  open_diligence_questions: memo.open_diligence_questions || [],
  confidence_scores: memo.confidence_scores || null,
  evaluator_score: typeof evaluator.evaluator_score === 'number' ? evaluator.evaluator_score : null,
  evaluator_feedback: evaluatorFeedback,
  source_documents: sourceDocuments,
};

return {
  json: {
    ...upstream,
    supabase_row: row,
  },
};

// Build Slack Message — Phase 3 task 3.16w
// Block Kit JSON for #investment-team. Highlights routing_decision,
// recommendation, top risks. Emoji + tone differs by routing.

// P-4: the immediate upstream is Insert Deal Memo (HTTP Request), which
// REPLACES $json with the Supabase REST response body. Reach back to
// Build Supabase Record (the last node that carried the full memo + eval
// payload) via cross-node reference. Capture the Supabase response
// status separately for downstream visibility.
const upstream = $('Build Supabase Record').item.json;
if (!upstream) throw new Error('Build Supabase Record item unavailable for Slack message.');
const supabaseResponse = $input.item.json;

const memo = upstream.memo_output || {};
const evaluator = upstream.evaluator_output || {};
const routing = evaluator.routing_decision || 'flagged_for_review';
const score = evaluator.evaluator_score;
const company = upstream.company_name || upstream.deal_id || 'Unknown deal';
const recommendation = memo.recommendation || 'unknown';

const headerEmoji = routing === 'complete_high_confidence' ? ':white_check_mark:'
                  : routing === 'complete' ? ':eight_spoked_asterisk:'
                  : ':rotating_light:';

const headerText = `${headerEmoji} ${company} — ${routing.replace(/_/g, ' ')}`;

const recommendationText = `*Recommendation (directional):* ${recommendation}`;
const scoreText = `*Evaluator score:* ${score != null ? `${score} / 60` : 'n/a'}`;

const risks = (memo.key_risks || [])
  .filter((r) => r && r.severity === 'HIGH')
  .slice(0, 3)
  .map((r) => `• *[${r.severity}]* ${r.risk}`)
  .join('\n');
const risksBlock = risks.length > 0 ? `*Top risks:*\n${risks}` : '_No HIGH-severity risks identified._';

const criticalIssues = (evaluator.critical_issues || [])
  .filter((c) => c && c.severity === 'HIGH')
  .slice(0, 3)
  .map((c) => `• [${c.issue_type}] ${c.description}`)
  .join('\n');
const criticalBlock = criticalIssues.length > 0 ? `*Evaluator critical issues:*\n${criticalIssues}` : '';

const summaryBlock = memo.executive_summary || '_No executive summary._';

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: headerText.slice(0, 150) } },
  { type: 'section', text: { type: 'mrkdwn', text: summaryBlock.slice(0, 3000) } },
  { type: 'section', fields: [
      { type: 'mrkdwn', text: recommendationText },
      { type: 'mrkdwn', text: scoreText },
    ]
  },
  { type: 'section', text: { type: 'mrkdwn', text: risksBlock.slice(0, 3000) } },
];
if (criticalBlock) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: criticalBlock.slice(0, 3000) } });
}
blocks.push({ type: 'context', elements: [
  { type: 'mrkdwn', text: `run_id: \`${upstream.run_id}\` · deal_id: \`${upstream.deal_id}\`` }
]});

return {
  json: {
    ...upstream,
    slack_payload: {
      text: headerText,  // fallback for clients that can't render blocks
      blocks,
    },
  },
};

// Build Error Record — Phase 3 task 3.17w
// The Error Trigger emits an item with shape:
//   { execution: {...}, workflow: {...}, node: {...}, error: {...} }
// We extract the failure context, attempt to recover run-level metadata
// from the Coordinator (if it ran), and assemble a minimal deal_memos
// row with status='error'.

const errorItem = $input.item.json;
const node = errorItem?.node?.name || 'unknown';
const errMsg = errorItem?.error?.message || errorItem?.execution?.error?.message || 'unknown error';
const errStack = errorItem?.error?.stack || '';
const executionId = errorItem?.execution?.id || null;

// Try to recover run-level metadata from upstream Coordinator. If the
// Coordinator never ran (e.g., Form Trigger failed), use placeholders.
let runId, dealId, companyName, sourceManifest = [];
try {
  const coord = $('Coordinator').all()[0]?.json;
  if (coord) {
    runId = coord.run_id;
    dealId = coord.deal_id;
    companyName = coord.company_name;
    sourceManifest = coord.documents || [];
  }
} catch (_) {
  // Coordinator not reachable; that's fine.
}

// Math.random fallback uuidv4 (per P-3, sandbox blocks crypto)
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

const row = {
  run_id: runId || uuidv4(),
  deal_id: dealId || 'unknown-deal',
  company_name: companyName || 'Unknown',
  status: 'error',
  evaluator_feedback: {
    schema_errors: [{
      agent: node,
      attempt_number: 1,
      error_path: '/' + node,
      message: errMsg.slice(0, 500),
    }],
    stack_trace: errStack.slice(0, 2000),
    execution_id: executionId,
  },
  source_documents: sourceManifest,
};

return {
  json: {
    error_row: row,
    error_summary: {
      node,
      message: errMsg,
      execution_id: executionId,
      run_id: row.run_id,
      deal_id: row.deal_id,
      company_name: row.company_name,
    },
  },
};

// Build Error Slack Message — Phase 3 task 3.17w
// Block Kit alert; uses :rotating_light: + warning emoji to distinguish
// from the green-path notifications.

const errorSummary = $('Build Error Record').item.json.error_summary;

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: `:rotating_light: Deal evaluation FAILED — ${errorSummary.company_name || 'Unknown'}` } },
  { type: 'section', fields: [
    { type: 'mrkdwn', text: `*Failed node:* \`${errorSummary.node}\`` },
    { type: 'mrkdwn', text: `*Execution id:* \`${errorSummary.execution_id || 'n/a'}\`` },
  ]},
  { type: 'section', text: { type: 'mrkdwn', text: `*Error:*\n\`\`\`${(errorSummary.message || '').slice(0, 1500)}\`\`\`` } },
  { type: 'context', elements: [
    { type: 'mrkdwn', text: `run_id: \`${errorSummary.run_id}\` · deal_id: \`${errorSummary.deal_id}\`` }
  ]},
];

return {
  json: {
    slack_payload: {
      text: `:rotating_light: Deal evaluation FAILED — ${errorSummary.company_name || 'Unknown'}`,
      blocks,
    },
  },
};

// Build Langfuse Batch — Phase 3 task 3.24/3.25/3.26/3.27
// Per design plan §3.12 fallback: manual instrumentation via
// /api/public/ingestion since our raw-HTTP chat-completions calls
// bypass the Langfuse community node's auto-wrapping.
//
// Emits one batch with: trace-create + observation-create per LLM call
// (GENERATION) + RFD as SPAN + score-create for evaluator score.

const upstream = $('Build Supabase Record').item.json;
if (!upstream) throw new Error('Build Langfuse Batch: Build Supabase Record item unavailable.');

const runId = upstream.run_id;
const dealId = upstream.deal_id;
const companyName = upstream.company_name;
const startedAt = upstream.timestamp_started;
const completedAt = $('Parse Evaluator Response').item.json.timestamp_completed || new Date().toISOString();

// Collect per-call usage from each Parse node.
function safeUsage(item) {
  const u = item?.json?.llm_usage || {};
  return {
    promptTokens: u.prompt_tokens || 0,
    completionTokens: u.completion_tokens || 0,
    totalTokens: u.total_tokens || (u.prompt_tokens || 0) + (u.completion_tokens || 0),
  };
}

const extractionItems = $('Parse Extraction Response').all() || [];
const contradictionItem = $('Parse Contradiction Response').all()[0];
const gapItem = $('Parse Gap Analysis Response').all()[0];
const pfItem = $('Parse Portfolio Fit Response').all()[0];
const memoItem = $('Parse Memo Response').all()[0];
const evalItem = $('Parse Evaluator Response').all()[0];

const model = upstream.llm_model || $env.ALICLOUD_MODEL || 'qwen3-max-2025-09-23';

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

const events = [];
const now = new Date().toISOString();

// 1. trace-create
events.push({
  id: uuidv4(),
  type: 'trace-create',
  timestamp: now,
  body: {
    id: runId,
    name: 'deal-diligence',
    userId: null,
    sessionId: runId,
    metadata: {
      deal_id: dealId,
      company_name: companyName,
      source_count: (upstream.source_manifest || []).length,
      evaluator_score: evalItem?.json?.evaluator_output?.evaluator_score ?? null,
      routing_decision: evalItem?.json?.evaluator_output?.routing_decision ?? null,
      recommendation: upstream.memo_output?.recommendation ?? null,
    },
    tags: ['phase-3'],
    timestamp: startedAt,
  },
});

// 2. observation-create for each LLM call (GENERATION).
// Timestamps are approximate: all calls share startedAt -> completedAt
// since per-call timing is not preserved in our workflow.
function gen(name, item, model) {
  if (!item) return;
  const usage = safeUsage(item);
  events.push({
    id: uuidv4(),
    type: 'observation-create',
    timestamp: now,
    body: {
      id: uuidv4(),
      traceId: runId,
      type: 'GENERATION',
      name,
      model,
      usage,
      startTime: startedAt,
      endTime: completedAt,
    },
  });
}

extractionItems.forEach((it, idx) => gen(`extraction-${idx}`, it, model));
gen('contradiction', contradictionItem, model);
gen('gap-analysis', gapItem, model);
gen('portfolio-fit', pfItem, model);
gen('memo-generation', memoItem, model);
gen('evaluator', evalItem, model);

// 3. RFD as a SPAN observation (no LLM, deterministic).
const rfdOutput = upstream.red_flag_detector_output || { red_flags: [] };
events.push({
  id: uuidv4(),
  type: 'observation-create',
  timestamp: now,
  body: {
    id: uuidv4(),
    traceId: runId,
    type: 'SPAN',
    name: 'red-flag-detector',
    metadata: {
      deterministic: true,
      flag_count: (rfdOutput.red_flags || []).length,
    },
    output: { red_flags: rfdOutput.red_flags || [] },
    startTime: startedAt,
    endTime: completedAt,
  },
});

// 4. score-create — Evaluator score as Langfuse Score.
const evaluatorScore = evalItem?.json?.evaluator_output?.evaluator_score;
if (typeof evaluatorScore === 'number') {
  events.push({
    id: uuidv4(),
    type: 'score-create',
    timestamp: now,
    body: {
      id: uuidv4(),
      traceId: runId,
      name: 'deal-diligence-quality',
      value: evaluatorScore,
      dataType: 'NUMERIC',
    },
  });
}

// 5. Auth header (Basic auth with public_key:secret_key, base64).
// 6. Host: try LANGFUSE_BASE_URL first (matches docker-compose passthrough
//    convention) then LANGFUSE_HOST (Langfuse Python SDK convention).
//    Both are recognized so .env is robust to either name.
const pk = $env.LANGFUSE_PUBLIC_KEY;
const sk = $env.LANGFUSE_SECRET_KEY;
const host = $env.LANGFUSE_BASE_URL || $env.LANGFUSE_HOST || 'https://cloud.langfuse.com';

// Diagnostic: print whether each env var reached the sandbox + first/last
// 4 chars of each key (NEVER the full secret). On 401 this tells us
// exactly which leg of the auth chain is broken.
function preview(s) {
  if (!s || typeof s !== 'string') return '(unset)';
  if (s.length < 12) return '(set, short)';
  return `${s.slice(0, 6)}...${s.slice(-4)} (len=${s.length})`;
}
console.log('[Langfuse diagnostic]',
  'pk:', preview(pk),
  '| sk:', preview(sk),
  '| host:', host,
  '| LANGFUSE_BASE_URL set:', !!$env.LANGFUSE_BASE_URL,
  '| LANGFUSE_HOST set:', !!$env.LANGFUSE_HOST
);

let auth = null;
if (pk && sk) {
  // Buffer is a Node global; available even in the sandboxed Code node.
  auth = 'Basic ' + Buffer.from(`${pk}:${sk}`).toString('base64');
}

return {
  json: {
    langfuse_batch: { batch: events },
    langfuse_auth: auth,
    langfuse_host: host,
    langfuse_event_count: events.length,
    langfuse_diagnostic: {
      pk_set: !!pk,
      sk_set: !!sk,
      host,
      base_url_env_set: !!$env.LANGFUSE_BASE_URL,
      host_env_set: !!$env.LANGFUSE_HOST,
    },
  },
};

// Build Markdown Memo — Phase 6 enhancement
// Renders the structured memo + evaluator + RFD + portfolio fit + sources
// into a single Markdown document. The next node (Write Memo File) writes
// this to /outputs/<deal_id>-<timestamp>.md inside the n8n container,
// which lands on the host at ./outputs/<deal_id>-<timestamp>.md.

const upstream = $input.item.json;
const evaluatorOutput = upstream.evaluator_output || {};
const rfdOutput = upstream.red_flag_detector_output || {};

// Reach back for the cleaned memo (post-citation-validation) and source manifest
const validateItem = $('Validate Memo Citations').all()[0]?.json;
const memoItem = $('Parse Memo Response').all()[0]?.json;
const cleanedMemo = (validateItem && validateItem.cleaned_memo) || (memoItem && memoItem.memo_output) || {};

const coordItem = $('Coordinator').all()[0]?.json;
const sourceManifest = (coordItem && coordItem.source_manifest) || upstream.source_manifest || [];

// Helpers
const sevEmoji = (sev) => ({ HIGH: '🔴', MEDIUM: '🟡', LOW: '🟢' }[sev] || '⚪');
const recLabel = (rec) => ({
  pass: '⬇️ Pass',
  pursue: '➡️ Pursue',
  advance_to_deep_diligence: '⬆️ Advance to deep diligence',
}[rec] || (rec || '—'));
const cite = (c) => c ? ` [${c}]` : '';
const fmt = (v) => (v === null || v === undefined || v === '') ? '—' : v;

const lines = [];

// Header
lines.push(`# ${cleanedMemo.company_name || upstream.company_name || 'Deal Memo'}`);
lines.push('');
lines.push(`**Deal ID:** \`${upstream.deal_id || ''}\`  `);
lines.push(`**Run ID:** \`${upstream.run_id || ''}\`  `);
lines.push(`**Generated:** ${new Date().toISOString()}  `);
lines.push(`**Recommendation:** ${recLabel(cleanedMemo.recommendation)}  `);
lines.push(`**Evaluator score:** ${fmt(evaluatorOutput.evaluator_score)} / 60  `);
lines.push(`**Routing:** \`${fmt(evaluatorOutput.routing_decision)}\``);
lines.push('');
lines.push('---');
lines.push('');

// Executive summary
if (cleanedMemo.executive_summary) {
  lines.push('## Executive Summary');
  lines.push('');
  lines.push(cleanedMemo.executive_summary);
  lines.push('');
}

// Recommendation rationale
if (cleanedMemo.recommendation_rationale) {
  lines.push('## Recommendation Rationale');
  lines.push('');
  lines.push(cleanedMemo.recommendation_rationale);
  lines.push('');
}

// Company snapshot
const cs = cleanedMemo.company_snapshot || {};
if (Object.keys(cs).length) {
  lines.push('## Company Snapshot');
  lines.push('');
  if (cs.description) lines.push(`- **Description:** ${cs.description}`);
  if (cs.stage) lines.push(`- **Stage:** ${cs.stage}`);
  if (cs.sector) lines.push(`- **Sector:** ${cs.sector}`);
  if (cs.headcount !== undefined && cs.headcount !== null) lines.push(`- **Headcount:** ${cs.headcount}`);
  if (cs.revenue) lines.push(`- **Revenue:** ${typeof cs.revenue === 'object' ? JSON.stringify(cs.revenue) : cs.revenue}`);
  if (cs.business_model) lines.push(`- **Business model:** ${cs.business_model}`);
  if (Array.isArray(cs.key_personnel) && cs.key_personnel.length) {
    lines.push(`- **Key personnel:** ${cs.key_personnel.join(', ')}`);
  }
  lines.push('');
}

// Investment thesis
if (cleanedMemo.investment_thesis) {
  lines.push('## Investment Thesis');
  lines.push('');
  lines.push(cleanedMemo.investment_thesis);
  lines.push('');
}

// Portfolio fit (call out early since this drives the recommendation)
const pf = cleanedMemo.portfolio_fit || {};
if (pf && Object.keys(pf).length) {
  lines.push('## Portfolio Fit (configured-investor thesis alignment)');
  lines.push('');
  if (pf.overall_thesis_alignment) lines.push(`- **Overall alignment:** \`${pf.overall_thesis_alignment}\``);
  if (pf.recommended_action) lines.push(`- **Recommended action:** \`${pf.recommended_action}\``);
  if (pf.strategic_fit && pf.strategic_fit.score !== null && pf.strategic_fit.score !== undefined) {
    lines.push(`- **Strategic fit:** ${pf.strategic_fit.score} — ${pf.strategic_fit.rationale || ''}`);
  }
  if (pf.stage_fit && pf.stage_fit.score !== null && pf.stage_fit.score !== undefined) {
    lines.push(`- **Stage fit:** ${pf.stage_fit.score} — ${pf.stage_fit.rationale || ''}`);
  }
  if (Array.isArray(pf.synergy_potential) && pf.synergy_potential.length) {
    lines.push('- **Synergies:**');
    for (const s of pf.synergy_potential) {
      lines.push(`  - ${s.portfolio_company} (${s.synergy_type}, **${s.strength}**): ${s.description || ''}`);
    }
  }
  if (Array.isArray(pf.anti_patterns) && pf.anti_patterns.length) {
    lines.push('- **Anti-patterns triggered:**');
    for (const a of pf.anti_patterns) {
      lines.push(`  - \`${a.pattern}\` — ${a.concern || ''}`);
    }
  }
  lines.push('');
}

// Key strengths
if (Array.isArray(cleanedMemo.key_strengths) && cleanedMemo.key_strengths.length) {
  lines.push('## Key Strengths');
  lines.push('');
  for (const s of cleanedMemo.key_strengths) {
    const text = s.claim || s.text || s.description || '';
    const c = s.citation || (Array.isArray(s.citations) && s.citations[0]) || null;
    lines.push(`- ${sevEmoji(s.severity)} **${s.severity || ''}** — ${text}${cite(c)}`);
  }
  lines.push('');
}

// Key risks
if (Array.isArray(cleanedMemo.key_risks) && cleanedMemo.key_risks.length) {
  lines.push('## Key Risks');
  lines.push('');
  for (const r of cleanedMemo.key_risks) {
    const text = r.claim || r.text || r.description || '';
    const c = r.citation || (Array.isArray(r.citations) && r.citations[0]) || null;
    lines.push(`- ${sevEmoji(r.severity)} **${r.severity || ''}** — ${text}${cite(c)}`);
  }
  lines.push('');
}

// Contradictions
if (Array.isArray(cleanedMemo.contradictions) && cleanedMemo.contradictions.length) {
  lines.push('## Contradictions');
  lines.push('');
  for (const c of cleanedMemo.contradictions) {
    lines.push(`- ${sevEmoji(c.severity)} **${c.severity || ''}** — ${c.description || c.summary || c.claim || ''}`);
    if (Array.isArray(c.sources) && c.sources.length) {
      lines.push(`  - Sources: ${c.sources.join(' vs ')}`);
    }
  }
  lines.push('');
}

// Red flags (deterministic — call out the audit-replay claim)
const flags = (rfdOutput.red_flags || []).slice();
if (flags.length) {
  lines.push('## Red Flags (deterministic, audit-replayable)');
  lines.push('');
  lines.push('_Detected via pure-JS pattern matching, no LLM. Same input → same output, every time._');
  lines.push('');
  for (const f of flags) {
    lines.push(`- ${sevEmoji(f.severity)} **${f.severity || ''}** — \`${f.flag_type || ''}\``);
    if (f.evidence) {
      if (f.evidence.source) lines.push(`  - Source: ${f.evidence.source}`);
      if (f.evidence.raw_text) {
        const trimmed = String(f.evidence.raw_text).replace(/\s+/g, ' ').trim();
        lines.push(`  - Raw text: > ${trimmed.length > 280 ? trimmed.slice(0, 280) + '…' : trimmed}`);
      }
      if (f.evidence.actual_value !== undefined) {
        lines.push(`  - Actual: \`${f.evidence.actual_value}\` (threshold: \`${f.evidence.threshold !== undefined && f.evidence.threshold !== null ? f.evidence.threshold : 'n/a'}\`)`);
      }
    }
  }
  lines.push('');
}

// Missing information
if (Array.isArray(cleanedMemo.missing_information) && cleanedMemo.missing_information.length) {
  lines.push('## Missing Information');
  lines.push('');
  for (const m of cleanedMemo.missing_information) {
    lines.push(`- **${m.importance || '?'}** [${m.category || '?'}] — ${m.item || m.description || ''}`);
  }
  lines.push('');
}

// Open diligence questions
if (Array.isArray(cleanedMemo.open_diligence_questions) && cleanedMemo.open_diligence_questions.length) {
  lines.push('## Open Diligence Questions');
  lines.push('');
  for (const q of cleanedMemo.open_diligence_questions) {
    const text = typeof q === 'string' ? q : (q.question || q.text || JSON.stringify(q));
    lines.push(`- ${text}`);
  }
  lines.push('');
}

// Evaluator detail
const evalCS = evaluatorOutput.criteria_scores || {};
if (Object.keys(evalCS).length) {
  lines.push('## Evaluator Detail (LLM-as-judge meta-evaluation)');
  lines.push('');
  lines.push('| Criterion | Score / 10 |');
  lines.push('|---|---|');
  lines.push(`| Citation completeness | ${fmt(evalCS.citation_completeness)} |`);
  lines.push(`| Contradiction acknowledgment | ${fmt(evalCS.contradiction_acknowledgment)} |`);
  lines.push(`| Missing-information coverage | ${fmt(evalCS.missing_information_coverage)} |`);
  lines.push(`| Red-flag propagation | ${fmt(evalCS.red_flag_propagation)} |`);
  lines.push(`| Reasoning coherence | ${fmt(evalCS.reasoning_coherence)} |`);
  lines.push(`| Hallucination check | ${fmt(evalCS.hallucination_check)} |`);
  lines.push(`| **Total** | **${fmt(evaluatorOutput.evaluator_score)} / 60** |`);
  lines.push('');
  if (Array.isArray(evaluatorOutput.critical_issues) && evaluatorOutput.critical_issues.length) {
    lines.push('### Critical Issues');
    lines.push('');
    for (const ci of evaluatorOutput.critical_issues) {
      lines.push(`- ${sevEmoji(ci.severity)} **${ci.severity || ''}** [\`${ci.issue_type || ''}\`] — ${ci.description || ''}`);
    }
    lines.push('');
  }
}

// Confidence scores
const conf = cleanedMemo.confidence_scores || {};
if (Object.keys(conf).length) {
  lines.push('## Confidence Scores');
  lines.push('');
  for (const [k, v] of Object.entries(conf)) {
    lines.push(`- **${k}:** ${v}`);
  }
  lines.push('');
}

// Source manifest
if (Array.isArray(sourceManifest) && sourceManifest.length) {
  lines.push('## Source Documents');
  lines.push('');
  for (const s of sourceManifest) {
    if (typeof s === 'string') {
      lines.push(`- ${s}`);
    } else if (s && s.source_name) {
      const parts = [s.source_name];
      if (s.source_type) parts.push(`type: ${s.source_type}`);
      if (s.page_count) parts.push(`${s.page_count} pages`);
      lines.push(`- ${parts.join(', ')}`);
    }
  }
  lines.push('');
}

// Footer
lines.push('---');
lines.push('');
lines.push(`_Generated by the Deal Diligence Workspace pipeline. Run \`${upstream.run_id || ''}\` at ${new Date().toISOString()}. The advance/pass decision belongs to the human reviewer (per project invariant I-1)._`);
lines.push('');

const markdown = lines.join('\n');

// Filename: <deal_id_safe>-<YYYYMMDD-HHMMSS>.md
const ts = new Date().toISOString().replace(/[:T-]/g, '').replace(/\..+/, '').slice(0, 15);
const dealIdSafe = String(upstream.deal_id || 'unknown').replace(/[^a-zA-Z0-9_-]/g, '_');
const filename = `${dealIdSafe}-${ts}.md`;

return {
  json: {
    ...upstream,
    memo_markdown_filename: filename,
  },
  binary: {
    memo_md: {
      data: Buffer.from(markdown, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: filename,
      fileExtension: 'md',
    },
  },
};
